function TM({team,size=80}:{team?:Team|null;size?:number}){if(!team)return null;if(team.imgUrl)return<div style={{width:size,height:size,borderRadius:size>100?24:16,overflow:"hidden",flexShrink:0,border:`3px solid ${team.cor1}40`,boxShadow:size>100?`0 8px 40px ${team.cor1}30`:undefined}}><img src={team.imgUrl} alt="" style={{width:"100%",height:"100%",objectFit:"cover"}}/></div>;const S=MS[team.mascot];return S?<S size={size}/>:null;}
function SB({label,value,color=C.gold}:{label:string;value:any;color?:string}){return<div style={{background:C.bgCard,border:`1px solid ${C.border}`,borderRadius:12,padding:"14px 20px",textAlign:"center",minWidth:100}}><div style={{fontSize:14,color:C.textMuted,textTransform:"uppercase",letterSpacing:2,marginBottom:6}}>{label}</div><div style={{fontSize:36,fontWeight:800,color,fontFamily:"'Cinzel',serif"}}>{typeof value==="number"?value.toLocaleString("pt-BR"):value}</div></div>;}
function PB({value,max,h=36}:{value:number;max:number;h?:number}){const p=max>0?Math.min((value/max)*100,100):0;return<div style={{position:"relative",height:h,background:"#0d0f14",borderRadius:6,overflow:"hidden",minWidth:120}}><div style={{height:"100%",width:`${p}%`,borderRadius:6,background:`linear-gradient(90deg,${BG(p)},${BG(p)}90)`,transition:"width .6s"}}/><span style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",fontSize:18,fontWeight:800,color:"#fff",textShadow:"0 1px 3px rgba(0,0,0,.6)"}}>{value}/{max}</span></div>;}
function Modal({open,onClose,title,children}:{open:boolean;onClose:()=>void;title:string;children:React.ReactNode}){if(!open)return null;return<div style={{position:"fixed",inset:0,zIndex:1000,display:"flex",alignItems:"center",justifyContent:"center"}} onClick={onClose}><div style={{position:"absolute",inset:0,background:"rgba(0,0,0,.8)",backdropFilter:"blur(8px)"}}/><div onClick={e=>e.stopPropagation()} style={{position:"relative",background:C.bgCard,border:`1px solid ${C.border}`,borderRadius:20,padding:32,width:"90%",maxWidth:600,maxHeight:"85vh",overflowY:"auto"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24}}><h3 style={{fontSize:22,fontWeight:800,color:C.gold,fontFamily:"'Cinzel',serif",margin:0}}>{title}</h3><button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.textMuted}}><X size={24}/></button></div>{children}</div></div>;}
function Inp({label,...p}:{label:string;[k:string]:any}){return<div style={{marginBottom:16}}><label style={{fontSize:14,color:C.textMuted,marginBottom:6,display:"block",textTransform:"uppercase",letterSpacing:1}}>{label}</label><input {...p} style={{width:"100%",padding:"12px 16px",background:C.bgInput,border:`1px solid ${C.border}`,borderRadius:8,color:C.text,fontSize:18,outline:"none",boxSizing:"border-box" as const,fontFamily:"'DM Sans',sans-serif"}}/></div>;}
function Sel({label,options,...p}:{label:string;options:{value:string;label:string}[];[k:string]:any}){return<div style={{marginBottom:16}}><label style={{fontSize:14,color:C.textMuted,marginBottom:6,display:"block",textTransform:"uppercase",letterSpacing:1}}>{label}</label><select {...p} style={{width:"100%",padding:"12px 16px",background:C.bgInput,border:`1px solid ${C.border}`,borderRadius:8,color:C.text,fontSize:18,fontFamily:"'DM Sans',sans-serif"}}>{options.map(o=><option key={o.value} value={o.value}>{o.label}</option>)}</select></div>;}
function Btn({children,gold,small,danger,...p}:{children:React.ReactNode;gold?:boolean;small?:boolean;danger?:boolean;[k:string]:any}){return<button {...p} style={{padding:small?"10px 18px":"14px 28px",borderRadius:10,border:gold?"none":danger?`1px solid ${C.red}40`:`1px solid ${C.border}`,background:gold?`linear-gradient(135deg,${C.gold},${C.goldDark})`:danger?`${C.red}15`:"transparent",color:gold?"#0b0c10":danger?C.red:C.text,fontSize:small?16:18,fontWeight:700,cursor:"pointer",fontFamily:"'DM Sans',sans-serif",display:"inline-flex",alignItems:"center",gap:8,...(p.style||{})}}>{children}</button>;}
const CT=({active,payload,label}:any)=>{if(!active||!payload?.length)return null;return<div style={{background:C.bgCard,border:`1px solid ${C.border}`,borderRadius:10,padding:"12px 16px",fontSize:16}}><div style={{color:C.textMuted,marginBottom:6}}>{label}</div>{payload.map((p:any,i:number)=><div key={i} style={{color:p.color||C.gold,fontWeight:700}}>{p.name}: {typeof p.value==="number"&&p.value>100?fB(p.value):p.value}</div>)}</div>;};
function RoleBadge({role}:{role:Role}){return<span style={{padding:"2px 10px",borderRadius:12,fontSize:12,fontWeight:800,background:`${ROLE_COLOR[role]}20`,color:ROLE_COLOR[role],textTransform:"uppercase",letterSpacing:1}}>{ROLE_LABEL[role]}</span>;}
// Counter cell with up/down buttons
function CC({value,onUp,onDown,color=C.text,size=26}:{value:number;onUp:()=>void;onDown:()=>void;color?:string;size?:number}){return<div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:4}}><button onClick={onDown} style={{background:"none",border:"none",cursor:"pointer",color:C.textDim,padding:4}}><ChevronDown size={size-6}/></button><span style={{fontWeight:900,fontSize:size,color,minWidth:28,textAlign:"center"}}>{value}</span><button onClick={onUp} style={{background:"none",border:"none",cursor:"pointer",color:C.gold,padding:4}}><ChevronUp size={size-6}/></button></div>;}

